/* ════════════════════════════════════════════════════════
   UTILITIES
════════════════════════════════════════════════════════ */
const pick = arr => arr[Math.floor(Math.random() * arr.length)];

/**
 * Sanitise a plain-text string so it cannot inject HTML when set via
 * textContent or later embedded in a safe container.
 * NOTE: for bot *text* segments we also HTML-encode via escapeHtml
 *       before inserting with innerHTML — see renderMarkdown().
 */
function sanitiseInput(raw) {
  // Trim, collapse whitespace, enforce hard length cap
  return String(raw).trim().replace(/\s+/g, ' ').slice(0, CONFIG.MAX_INPUT_LEN);
}

/** Escape for safe innerHTML insertion (text-only segments). */
function escapeHtml(s) {
  return s
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#x27;');
}

/**
 * renderMarkdown — converts our limited markdown to safe HTML.
 * Input is ALREADY html-escaped so **bold** etc are applied on safe text.
 */
function renderMarkdown(raw) {
  let s = escapeHtml(raw);

  // Bold / italic
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  s = s.replace(/\*(.+?)\*/g,     '<em>$1</em>');

  // Bullet items (• or -)
  s = s.replace(/^[•\-]\s(.+)$/gm, '<li>$1</li>');

  // Horizontal rule
  s = s.replace(/^---$/gm, '<hr>');

  // Wrap paragraphs (split on blank lines)
  const blocks = s.split(/\n\n+/);
  s = blocks.map(b => {
    if (/^<(li|hr|ul)/.test(b.trim())) {
      // Wrap consecutive <li> in <ul>
      return b.includes('<li>') ? `<ul>${b}</ul>` : b;
    }
    return `<p>${b.replace(/\n/g, '<br>')}</p>`;
  }).join('');

  return s;
}

/* ════════════════════════════════════════════════════════
   MESSAGE SEGMENT BUILDERS
   Each builder returns an array of segments:
     { type: 'text', content: '...' }   → rendered via renderMarkdown (XSS-safe)
     { type: 'html', content: '...' }   → inserted directly (trusted internal HTML only)
   This is the fix: text and HTML never get mixed into one string,
   so HTML tags can never accidentally be printed as raw text.
════════════════════════════════════════════════════════ */

/** Build the question display card — read-only, no click interaction. */
function buildQuestionHTML(q, idx, total) {
  const opts = Object.entries(q.opts).map(([l, text]) => {
    const safeText = escapeHtml(text);
    return `<div class="q-option">
              <span class="opt-letter">${l}</span>
              <span>${safeText}</span>
            </div>`;
  }).join('');
  const safeQ = escapeHtml(q.q);
  return `<div class="q-card">
    <div class="q-num">Question ${idx + 1} of ${total}</div>
    <div class="q-text">${safeQ}</div>
    <div class="q-options">${opts}</div>
    <div class="q-hint">💬 Type A, B, C, or D in the box below to answer.</div>
  </div>`;
}

/** Build the result card (trusted internal HTML). */
function buildResultHTML(score, total, lesson) {
  const pct    = Math.round((score / total) * 100);
  const passed = pct >= 90;
  const label  = passed ? 'Passed! ✅' : 'Keep going! 💪';
  const msg    = passed
    ? "You've demonstrated a strong understanding of DHH awareness and workplace inclusion. Excellent work!"
    : "You're building a solid foundation! A score of 90%+ unlocks the next module. Reviewing the lesson will help you get there.";
  const btnClass = passed ? ''      : 'retry';
  const btnText  = passed ? '👉 Continue to Module 2' : '📖 Revisit Module 1';
  const btnHref  = passed ? escapeHtml(lesson.nextUrl) : escapeHtml(lesson.url);

  return `<div class="result-card">
    <div class="result-score">${score}/${total}</div>
    <div class="result-label">${pct}% — ${label}</div>
    <div class="result-body">${msg}</div>
    <a href="${btnHref}" target="_blank" rel="noopener noreferrer"
       class="result-cta ${btnClass}">${btnText}</a>
  </div>`;
}

