/* ════════════════════════════════════════════════════════
   INTENT DETECTION
════════════════════════════════════════════════════════ */
function detectIntent(t) {
  t = t.toLowerCase().trim();
  if (/^[abcd]$/.test(t) ||
      /\b(answer\s*is|i\s*(choose|pick|select|think|go\s*with))\s*[abcd]\b/.test(t)) return 'ANSWER';
  if (/\b(hello|hi|hey|howdy|greetings|good\s*(morning|afternoon|evening))\b/.test(t)) return 'GREETING';
  if (/\b(great|good|fine|well|fantastic|wonderful|amazing|excellent|not\s*bad|pretty\s*good|doing\s*well|happy|excited)\b/.test(t)) return 'WB_POS';
  if (/\b(bad|tired|not\s*(great|good|okay|well)|terrible|awful|stressed|rough|sad|meh)\b/.test(t)) return 'WB_NEG';
  if (/\b(start|begin|ready|let'?s\s*go|go\s*ahead|ok|okay|sure|yes|yep|yeah|absolutely|sounds\s*good)\b/.test(t)) return 'START';
  if (/\b(help|how\s*does\s*this\s*work|instructions|guide|what\s*(do|should)\s*i\s*do)\b/.test(t)) return 'HELP';
  if (/\b(confused|don'?t\s*understand|huh|unclear|lost|not\s*sure\s*(what|how)|what\s*(do\s*you\s*mean|now))\b/.test(t)) return 'CONFUSED';
  if (/\b(what|how|why|tell\s*me|explain|describe|define|meaning|difference)\b/.test(t)) return 'QUESTION';
  return 'UNKNOWN';
}

function extractLetter(t) {
  const m = t.toLowerCase().match(/\b([abcd])\b/);
  return m ? m[1].toUpperCase() : '';
}

function searchKB(t) {
  t = t.toLowerCase();
  for (const entry of KB) {
    if (entry.kw.some(k => t.includes(k))) return entry.a;
  }
  return null;
}


